document.addEventListener("DOMContentLoaded",function(){window.addEventListener("load",()=>{var e=getObject("#sort-box"),e;e&&(e.addEventListener("change",function(){fetch(`https://${window.location.hostname}/wp-admin/admin-ajax.php`,{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded"},body:new URLSearchParams({action:"update_meta",type:"user",key:"profile-sort",value:this.value})}).then(()=>window.location.reload())}),e=getObject("#search-box"))&&e.addEventListener("input",function(){let a=this.value.toLowerCase();getObjects("a.link-profiles").forEach(e=>{var t=e.getAttribute("data-user").toLowerCase();e.classList.toggle("hide-profile",!t.includes(a))})})})});